// Calculate AR/AP totals and group by due date bucket: 0-30, 31-60, 61-90
const invoiceItems = $('Read Outstanding Invoices').all();
const billItems = $('Read Unpaid Bills').all();
const today = new Date();

function daysBetween(date1, date2) {
  const d1 = new Date(date1);
  const d2 = new Date(date2);
  return Math.ceil((d1 - d2) / (1000 * 60 * 60 * 24));
}

function getBucket(dueDate) {
  const daysUntilDue = daysBetween(dueDate, today);
  if (daysUntilDue <= 30) return '0-30';
  if (daysUntilDue <= 60) return '31-60';
  if (daysUntilDue <= 90) return '61-90';
  return '90+';
}

// Process Accounts Receivable (invoices = money coming in)
const arBuckets = { '0-30': 0, '31-60': 0, '61-90': 0, '90+': 0 };
let arTotal = 0;
const arDetails = [];

for (const item of invoiceItems) {
  const d = item.json;
  const amount = parseFloat(d.Amount || d['Amount Due'] || d.Total || 0);
  const dueDate = d['Due Date'] || d.DueDate || d.Date || today.toISOString();
  const bucket = getBucket(dueDate);
  arBuckets[bucket] += amount;
  arTotal += amount;
  arDetails.push({
    invoiceNumber: d['Invoice Number'] || d.Number || 'N/A',
    client: d.Client || d.Contact || d.Customer || 'Unknown',
    amount,
    dueDate,
    bucket,
    daysUntilDue: daysBetween(dueDate, today),
  });
}

// Process Accounts Payable (bills = money going out)
const apBuckets = { '0-30': 0, '31-60': 0, '61-90': 0, '90+': 0 };
let apTotal = 0;
const apDetails = [];

for (const item of billItems) {
  const d = item.json;
  const amount = parseFloat(d.Amount || d['Amount Due'] || d.Total || 0);
  const dueDate = d['Due Date'] || d.DueDate || d.Date || today.toISOString();
  const bucket = getBucket(dueDate);
  apBuckets[bucket] += amount;
  apTotal += amount;
  apDetails.push({
    billNumber: d['Bill Number'] || d.Reference || 'N/A',
    supplier: d.Supplier || d.Vendor || d.Contact || 'Unknown',
    amount,
    dueDate,
    bucket,
    daysUntilDue: daysBetween(dueDate, today),
  });
}

// Net cash flow per bucket
const netCashFlow = {};
for (const bucket of ['0-30', '31-60', '61-90', '90+']) {
  netCashFlow[bucket] = arBuckets[bucket] - apBuckets[bucket];
}

return {
  json: {
    reportDate: today.toISOString().split('T')[0],
    accountsReceivable: {
      total: arTotal,
      buckets: arBuckets,
      invoiceCount: invoiceItems.length,
      topInvoices: arDetails.sort((a, b) => b.amount - a.amount).slice(0, 5),
    },
    accountsPayable: {
      total: apTotal,
      buckets: apBuckets,
      billCount: billItems.length,
      topBills: apDetails.sort((a, b) => b.amount - a.amount).slice(0, 5),
    },
    netCashFlow,
    netPosition: arTotal - apTotal,
    currency: 'ZAR',
  }
};

